#!/usr/bin/env python3
# ruff: noqa: T201 allow print statements
"""
CI guard: the data-warehouse API/presentation layer must stay source-agnostic.

Per-source behaviour (``if source_type == ExternalDataSourceType.POSTGRES``,
``source.is_direct_snowflake``, …) keeps getting bolted onto the DWH views. Every
such branch splits "how source X behaves" between the source class and the API
layer, and grows the views without bound. The API should ask *what a source
supports* and delegate the *how*, never naming a concrete source type. Depending
on the concern that means a capability flag / mixin on the source
(``products/warehouse_sources/.../sources/common``) or an engine-keyed adapter
dispatched on ``source.direct_engine`` for direct-query behaviour. See
``products/data_warehouse/backend/presentation/README.md``.

This is a shrink-only baseline (the same shape as the IDOR fail-closed guard):

- Each forbidden reference is counted per ``(file, token)``.
- A NEW ``(file, token)`` key, or a HIGHER count for an existing one, fails CI —
  that's a new per-source branch.
- A LOWER count (a family migrated to a capability) is reported as an
  opportunity to shrink the baseline; regenerate to bank the win.

The baseline is the mechanical output of ``--regenerate-baseline`` — do not hand
edit it, or it degrades into a curated allowlist.

Usage:
    python check-dwh-source-agnostic.py
    python check-dwh-source-agnostic.py --regenerate-baseline

Exit codes:
    0 - No new per-source branches (may pass with shrink warnings)
    1 - New per-source branch(es) added to the presentation layer
"""

import re
import sys
import argparse
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent.parent
SCAN_ROOT = REPO_ROOT / "products/data_warehouse/backend/presentation"
BASELINE_FILE = SCAN_ROOT / "source_agnostic_baseline.txt"

# Structural signals that the API layer is naming a concrete source type. Kept
# deliberately narrow (enum member refs + the model's `is_direct_*` engine
# properties) — the two patterns the branches always take. Bare imports
# (`from ... import ExternalDataSourceType`) don't match: they carry no `.MEMBER`.
FORBIDDEN_PATTERNS = [
    re.compile(r"\bExternalDataSourceType\.[A-Z][A-Z0-9_]*\b"),
    re.compile(r"\bSourceType\.[A-Z][A-Z0-9_]*\b"),
    re.compile(r"\bis_direct_(?:postgres|mysql|snowflake|redshift)\b"),
]

BASELINE_HEADER = (
    "# Per-source branches still living in the DWH presentation layer.\n"
    "#\n"
    "# DO NOT EDIT BY HAND. This file is the mechanical output of\n"
    "# `--regenerate-baseline`. Hand-adding entries turns it back into a curated\n"
    "# allowlist and defeats the shrink-only guarantee.\n"
    "#\n"
    "# Auto-generated by .github/scripts/check-dwh-source-agnostic.py\n"
    "# Regenerate: python .github/scripts/check-dwh-source-agnostic.py --regenerate-baseline\n"
    "#\n"
    "# Each line is `<count>\\t<token>\\t<relpath>`. Migrate a family to a capability\n"
    "# mixin (see .../sources/common/capabilities.py), then regenerate to shrink.\n"
)


def scan_current() -> dict[tuple[str, str], int]:
    """Count forbidden per-source references, keyed on (relpath, matched token)."""
    counts: dict[tuple[str, str], int] = {}
    for path in sorted(SCAN_ROOT.rglob("*.py")):
        if path.name.startswith("test_") or "/tests/" in path.as_posix():
            continue
        relpath = path.relative_to(REPO_ROOT).as_posix()
        text = path.read_text()
        for pattern in FORBIDDEN_PATTERNS:
            for match in pattern.finditer(text):
                key = (relpath, match.group(0))
                counts[key] = counts.get(key, 0) + 1
    return counts


def read_baseline() -> dict[tuple[str, str], int]:
    if not BASELINE_FILE.exists():
        return {}
    baseline: dict[tuple[str, str], int] = {}
    for line in BASELINE_FILE.read_text().splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        count_str, token, relpath = line.split("\t")
        baseline[(relpath, token)] = int(count_str)
    return baseline


def write_baseline(counts: dict[tuple[str, str], int]) -> None:
    lines = sorted(f"{count}\t{token}\t{relpath}" for (relpath, token), count in counts.items())
    body = "\n".join(lines) + ("\n" if lines else "")
    BASELINE_FILE.write_text(BASELINE_HEADER + body)


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--regenerate-baseline",
        action="store_true",
        help="Rewrite the baseline from the current presentation-layer state.",
    )
    args = parser.parse_args()

    current = scan_current()

    print("=" * 60)
    print("DWH source-agnostic presentation-layer guard")
    print("=" * 60)

    if args.regenerate_baseline:
        write_baseline(current)
        total = sum(current.values())
        print(f"\n  Regenerated {BASELINE_FILE.relative_to(REPO_ROOT)}")
        print(f"  {total} per-source reference(s) across {len(current)} (file, token) pair(s).")
        return 0

    baseline = read_baseline()

    new_branches: list[tuple[str, str, int, int]] = []  # relpath, token, baseline_count, current_count
    for key, count in sorted(current.items()):
        base = baseline.get(key, 0)
        if count > base:
            new_branches.append((key[0], key[1], base, count))

    shrunk: list[tuple[str, str, int, int]] = []
    for key, base in sorted(baseline.items()):
        count = current.get(key, 0)
        if count < base:
            shrunk.append((key[0], key[1], base, count))

    print(f"\n  Baseline: {sum(baseline.values())} references")
    print(f"  Current:  {sum(current.values())} references")

    if new_branches:
        joined = ", ".join(f"{token} in {relpath}" for relpath, token, _, _ in new_branches)
        print(f"::error::New per-source branch(es) in the DWH presentation layer: {joined}")
        print(f"\n  ❌ ERROR: {len(new_branches)} new per-source reference(s):")
        for relpath, token, base, count in new_branches:
            print(f"     - {token}  ({base} → {count})  in {relpath}")
        print("\n  The API/presentation layer must not name a concrete source type.")
        print("  Expose the behaviour on the source (a _BaseSource capability flag or a")
        print("  capability mixin) or, for direct-query engine behaviour, an engine-keyed")
        print("  adapter dispatched on source.direct_engine — never a source-type branch.")
        print("  See products/data_warehouse/backend/presentation/README.md.")
        return 1

    if shrunk:
        print(f"\n  ✅ {len(shrunk)} reference(s) migrated since baseline (regenerate to shrink):")
        for relpath, token, base, count in shrunk:
            print(f"     - {token}  ({base} → {count})  in {relpath}")
        print("\n  Run: python .github/scripts/check-dwh-source-agnostic.py --regenerate-baseline")
        print("\n⚠️  PASSED with shrink opportunities.")
        return 0

    print("\n✅ No new per-source branches. Baseline matches.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
